using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
char a[505][505];
int dp[505][505][2];
signed main(){
    int t;
    cin >> t;
    while (t --) {
        int n, m, x;
        cin >> n >> m >> x;
        for(int i = 1; i <= n; i ++) {
            for (int j = 1; j <= m; j ++) {
                cin >> a[i][j];
            }
        }
        for (int k = 0; k <= x; k ++) {
            for (int i = 1; i <= n; i ++) {
                for (int j = 1; j <= m; j ++) {
                    if (a[i][j] == '0') dp[i][j][k & 1] = max(dp[i - 1][j][k & 1], dp[i][j - 1][k & 1]);
                    if (a[i][j] == '1') dp[i][j][k & 1] = max(dp[i - 1][j][k & 1], dp[i][j - 1][k & 1]) + 1;
                    if (a[i][j] == '?') 
                        if (k == 0) dp[i][j][k & 1] = max(dp[i - 1][j][k & 1], dp[i][j - 1][k & 1]);
                        else dp[i][j][k & 1]= max(max(dp[i - 1][j][(k - 1) & 1], dp[i][j - 1][(k - 1) & 1]) + 1, max(dp[i - 1][j][k & 1], dp[i][j - 1][k & 1]));
                }
            }
        }
        cout << dp[n][m][x & 1] << '\n';
    }
    return 0;
}
